const body = $json.body || $json;
const text = String(body.message || body.text || body.body || '').trim();
const phone = String(body.phone || body.from || '').trim();
const userName = String(body.userName || body.name || 'Cliente WhatsApp').trim();
const operatorLogin = String(body.operatorLogin || 'operador01').trim();
const groupId = String(body.groupId || body.chatId || '').trim();
const userId = String(body.userId || phone || '').trim();
const amountMatch = text.match(/(\d+[\.,]?\d{0,2})/);
const amount = amountMatch ? amountMatch[1].replace('.', ',') : '';
const externalId = `${groupId || 'pv'}-${userId || 'user'}-${Date.now()}`;
return [{ json: { text, phone, userName, operatorLogin, groupId, userId, amount, externalId } }];

const original = $('Normalizar Mensagem').first().json;
const charge = $json.data || {};
return [{ json: {
  success: true,
  phone: original.phone,
  groupId: original.groupId,
  userId: original.userId,
  userName: original.userName,
  externalId: original.externalId,
  reference: charge.reference || '',
  amount: charge.amountFormatted || '',
  code: charge.code || '',
  image: charge.image || '',
  state: charge.state || 'pending',
  replyText: charge.message || `Pagamento gerado com sucesso.\n\nValor: ${charge.amountFormatted || ''}\nReferencia: ${charge.reference || ''}\n\nPIX copia e cola:\n${charge.code || ''}`
} }];

const data = $('Normalizar Mensagem').first().json;
return [{ json: {
  success: false,
  phone: data.phone,
  groupId: data.groupId,
  userId: data.userId,
  userName: data.userName,
  replyText: 'Envie um valor valido. Exemplo: pix 150,00'
} }];
